import { ResponsiveLine } from '@nivo/line';

import React from 'react';
import { getAltitude } from '../data/altitudeData';

const AltitudeChart = (props) => {
	return (
		<ResponsiveLine
			data={getAltitude(props.date, props.latitude, props.longitude)}
			margin={{ top: 50, right: 110, bottom: 50, left: 60 }}
			xScale={{ type: 'point' }}
			yScale={{
				type: 'linear',
				min: 'auto',
				max: 'auto',
				stacked: true,
				reverse: false,
			}}
			yFormat=' >-.2f'
			axisTop={null}
			axisRight={{
				orient: 'right',
				tickSize: 5,
				tickPadding: 5,
				tickRotation: 0,
				legendOffset: -40,
				legendPosition: 'middle',
			}}
			axisBottom={{
				orient: 'bottom',
				tickSize: 5,
				tickPadding: 5,
				tickRotation: 0,
				legendOffset: 36,
				legendPosition: 'middle',
			}}
			axisLeft={{
				orient: 'left',
				tickSize: 5,
				tickPadding: 5,
				tickRotation: 0,
				legendOffset: -40,
				legendPosition: 'middle',
			}}
			colors='#ed673b'
			lineWidth={5}
			enablePoints={false}
			pointSize={10}
			pointColor={{ theme: 'background' }}
			pointBorderWidth={2}
			pointBorderColor={{ from: 'serieColor' }}
			pointLabelYOffset={-12}
			enableArea={true}
			areaOpacity={0.35}
			useMesh={true}
      markers={[
        {
          axis: "y",
          value: 0,
          lineStyle: { stroke: '0413e', strokeWidth: 2 },
        }
      ]}
      // theme={{
      //   axis: {
      //     ticks: {
      //       line: {
      //         stroke: "green"
      //       },
      //       text: {
      //         fill: "red"
      //       }
      //     }
      //   },
      //   grid: {
      //     line: {
      //       STROKE: 'BLACK'
      //     }
      //   }
      // }
      // }
		/>
	);
};

export default AltitudeChart;
